// eval/frontier/plot.ts — per-task SVG scatter plots of the Pareto frontier.
//
// Produces one SVG per task class, with all measured (cost, quality)
// points scattered and the Pareto-optimal frontier connected by a stepped
// line. SVG is generated by hand (no dependency) so we ship one fewer
// runtime dep — the plots are read-only artifacts shipped alongside the
// frontier JSON.
//
// Layout per plot:
//
//   ┌───────────────────────────────────────────────┐
//   │  Pareto Frontier — qa                          │
//   │  cost vs quality (50 examples / model)         │
//   │                                                │
//   │   1.0 ┤    ●               ●─────●            │
//   │       │              ●        ●               │
//   │   0.5 ┤        ●                              │
//   │       │  ●                                    │
//   │   0.0 └────────────────────────────────────── │
//   │       0      $0.001     $0.01    $0.1         │
//   │             mean cost per call (log scale)     │
//   └───────────────────────────────────────────────┘
//
// Axes:
//   - X: mean cost USD per call, log-scaled. Linear-scale plots are
//     unreadable because cost spans 4+ orders of magnitude (free Groq vs
//     Opus 4.7 paid).
//   - Y: mean quality in [0, 1], linear. Bounded above by 1 so the plot
//     always shows the same vertical range.
//
// Conventions:
//   - Frontier points: filled diamonds + connecting stepped line.
//   - Dominated points: hollow circles.
//   - Tooltips: SVG `<title>` per point with model id, cost, quality, n.

import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

import type { TaskClass } from "../../packages/core/src/types.ts";
import type { AllEntry, FrontierFile, FrontierTaskBlock } from "./_types.ts";

const DEFAULT_RESULTS_DIR: string = (() => {
  const here = dirname(fileURLToPath(import.meta.url));
  return join(here, "..", "results");
})();

// ---------------------------------------------------------------------------
// Plot dimensions
// ---------------------------------------------------------------------------

const PLOT_W = 720;
const PLOT_H = 420;
const MARGIN = { top: 60, right: 40, bottom: 60, left: 70 } as const;
const INNER_W = PLOT_W - MARGIN.left - MARGIN.right;
const INNER_H = PLOT_H - MARGIN.top - MARGIN.bottom;

// ---------------------------------------------------------------------------
// Coordinate scales
// ---------------------------------------------------------------------------

/**
 * Build a log10 scale mapping [costMin, costMax] → [0, INNER_W]. Cost = 0
 * is plotted at the left edge with a tiny offset (LOG_EPSILON) so the log
 * still has a defined value.
 */
const LOG_EPSILON = 1e-9;

interface Scale {
  domain: [number, number];
  range: [number, number];
  map: (x: number) => number;
}

function logScale(min: number, max: number, range: [number, number]): Scale {
  const m = Math.max(LOG_EPSILON, min);
  const M = Math.max(m * 1.001, max);
  const lm = Math.log10(m);
  const lM = Math.log10(M);
  return {
    domain: [m, M],
    range,
    map: (x: number) => {
      const lx = Math.log10(Math.max(LOG_EPSILON, x));
      const frac = (lx - lm) / (lM - lm);
      return range[0] + frac * (range[1] - range[0]);
    },
  };
}

function linearScale(min: number, max: number, range: [number, number]): Scale {
  const m = min;
  const M = max === min ? min + 1 : max;
  return {
    domain: [m, M],
    range,
    map: (x: number) => {
      const frac = (x - m) / (M - m);
      return range[0] + frac * (range[1] - range[0]);
    },
  };
}

// ---------------------------------------------------------------------------
// SVG helpers
// ---------------------------------------------------------------------------

function escapeXml(s: string): string {
  return s
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

function fmtCost(c: number): string {
  if (c === 0) return "$0";
  if (c < 0.0001) return `$${c.toExponential(2)}`;
  if (c < 0.01) return `$${c.toFixed(5)}`;
  return `$${c.toFixed(4)}`;
}

function fmtQuality(q: number): string {
  return q.toFixed(3);
}

/**
 * Render an SVG plot for one task's frontier block. Pure: same input →
 * byte-identical output. Tests assert on the SVG string directly.
 */
export function renderTaskPlot(task: TaskClass, block: FrontierTaskBlock): string {
  const allEntries = block.all;
  // Empty-task short-circuit: emit a plot with just the axes + a "no data"
  // label. Keeps the artifact shape consistent across task classes.
  if (allEntries.length === 0) {
    return emptyPlot(task);
  }

  // Cost: log scale across observed range, fall back to 1e-6 if min is 0.
  const costs = allEntries.map((e) => e.mean_cost_usd);
  const costMin = Math.max(LOG_EPSILON, Math.min(...costs.filter((c) => c > 0), 1e-6));
  const costMax = Math.max(...costs, costMin * 10);
  const x = logScale(costMin, costMax, [0, INNER_W]);
  // Quality: linear in [0, 1]. We invert Y so 1.0 is at top.
  const y = linearScale(0, 1, [INNER_H, 0]);

  const tickCostsExp = (() => {
    const lo = Math.floor(Math.log10(costMin));
    const hi = Math.ceil(Math.log10(costMax));
    const out: number[] = [];
    for (let p = lo; p <= hi; p++) out.push(10 ** p);
    return out;
  })();
  const tickQualities = [0, 0.25, 0.5, 0.75, 1];

  const lines: string[] = [];
  lines.push(
    `<svg xmlns="http://www.w3.org/2000/svg" width="${PLOT_W}" height="${PLOT_H}" viewBox="0 0 ${PLOT_W} ${PLOT_H}" font-family="-apple-system, BlinkMacSystemFont, sans-serif">`,
  );
  lines.push(`<rect width="${PLOT_W}" height="${PLOT_H}" fill="white"/>`);

  // Title block.
  lines.push(
    `<text x="${PLOT_W / 2}" y="26" text-anchor="middle" font-size="18" font-weight="600">Pareto Frontier — ${escapeXml(task)}</text>`,
  );
  const sampleSizes = allEntries.map((e) => e.n);
  const nMin = Math.min(...sampleSizes);
  const nMax = Math.max(...sampleSizes);
  const subtitle =
    nMin === nMax
      ? `${nMin} examples per model · ${block.frontier.length} on frontier · ${block.dominated.length} dominated`
      : `${nMin}–${nMax} examples per model · ${block.frontier.length} on frontier · ${block.dominated.length} dominated`;
  lines.push(
    `<text x="${PLOT_W / 2}" y="46" text-anchor="middle" font-size="12" fill="#555">${escapeXml(subtitle)}</text>`,
  );

  // Plot area frame.
  const ox = MARGIN.left;
  const oy = MARGIN.top;
  lines.push(`<g transform="translate(${ox} ${oy})">`);
  lines.push(`<rect x="0" y="0" width="${INNER_W}" height="${INNER_H}" fill="#fafafa" stroke="#ddd"/>`);

  // Y gridlines + labels.
  for (const q of tickQualities) {
    const yy = y.map(q);
    lines.push(`<line x1="0" y1="${yy}" x2="${INNER_W}" y2="${yy}" stroke="#eee"/>`);
    lines.push(
      `<text x="-8" y="${yy + 4}" text-anchor="end" font-size="10" fill="#555">${fmtQuality(q)}</text>`,
    );
  }
  // X gridlines + labels.
  for (const c of tickCostsExp) {
    const xx = x.map(c);
    if (xx < -1 || xx > INNER_W + 1) continue;
    lines.push(`<line x1="${xx}" y1="0" x2="${xx}" y2="${INNER_H}" stroke="#eee"/>`);
    lines.push(
      `<text x="${xx}" y="${INNER_H + 16}" text-anchor="middle" font-size="10" fill="#555">${escapeXml(fmtCost(c))}</text>`,
    );
  }

  // Axis labels.
  lines.push(
    `<text x="${INNER_W / 2}" y="${INNER_H + 42}" text-anchor="middle" font-size="12" fill="#333">mean cost per call (log scale)</text>`,
  );
  lines.push(
    `<text transform="translate(-46 ${INNER_H / 2}) rotate(-90)" text-anchor="middle" font-size="12" fill="#333">mean quality</text>`,
  );

  // Frontier line (stepped).
  if (block.frontier.length > 1) {
    const sorted = block.frontier
      .slice()
      .sort((a, b) => a.mean_cost_usd - b.mean_cost_usd);
    let d = "";
    sorted.forEach((p, i) => {
      const px = x.map(p.mean_cost_usd);
      const py = y.map(p.mean_quality);
      if (i === 0) d += `M ${px} ${py}`;
      else {
        const prev = sorted[i - 1]!;
        const prevX = x.map(prev.mean_cost_usd);
        const prevY = y.map(prev.mean_quality);
        // Stepped: hold prevY until px, then step up to py.
        d += ` L ${px} ${prevY} L ${px} ${py}`;
        // Reference prevX so the variable is "used" (lint clean). It's
        // already encoded into the start of this segment.
        if (prevX < 0) d += "";
      }
    });
    lines.push(`<path d="${d}" stroke="#0a7" stroke-width="2" fill="none"/>`);
  }

  // Sort entries so dominated drawn first (under), frontier on top.
  const ordered = [...allEntries].sort((a, b) => {
    if (a.dominated === b.dominated) return 0;
    return a.dominated ? -1 : 1;
  });
  for (const e of ordered) {
    const px = x.map(e.mean_cost_usd);
    const py = y.map(e.mean_quality);
    const tip = `${e.model} · cost=${fmtCost(e.mean_cost_usd)} · quality=${fmtQuality(e.mean_quality)} · n=${e.n} · ${e.tokenSource} (${e.confidence})`;
    if (e.dominated) {
      lines.push(
        `<circle cx="${px}" cy="${py}" r="4" fill="white" stroke="#999" stroke-width="1.2"><title>${escapeXml(tip)}</title></circle>`,
      );
    } else {
      // Diamond (rotated square) for frontier points.
      const r = 5.5;
      lines.push(
        `<rect x="${px - r}" y="${py - r}" width="${r * 2}" height="${r * 2}" transform="rotate(45 ${px} ${py})" fill="#0a7"><title>${escapeXml(tip)}</title></rect>`,
      );
    }
  }

  // Labels (model id) next to each point. Small font to avoid overlap.
  for (const e of allEntries) {
    const px = x.map(e.mean_cost_usd);
    const py = y.map(e.mean_quality);
    lines.push(
      `<text x="${px + 8}" y="${py - 6}" font-size="9" fill="#333">${escapeXml(e.model)}</text>`,
    );
  }

  // Legend.
  const legendX = INNER_W - 130;
  const legendY = 12;
  lines.push(
    `<rect x="${legendX - 8}" y="${legendY - 10}" width="138" height="44" fill="white" stroke="#ddd"/>`,
  );
  lines.push(
    `<rect x="${legendX}" y="${legendY + 2}" width="10" height="10" transform="rotate(45 ${legendX + 5} ${legendY + 7})" fill="#0a7"/>`,
  );
  lines.push(
    `<text x="${legendX + 18}" y="${legendY + 11}" font-size="10" fill="#333">frontier</text>`,
  );
  lines.push(
    `<circle cx="${legendX + 5}" cy="${legendY + 24}" r="4" fill="white" stroke="#999" stroke-width="1.2"/>`,
  );
  lines.push(
    `<text x="${legendX + 18}" y="${legendY + 27}" font-size="10" fill="#333">dominated</text>`,
  );

  lines.push("</g>");
  lines.push("</svg>");
  return lines.join("\n");
}

/**
 * Plot used when a task class has no measurements yet.
 */
function emptyPlot(task: TaskClass): string {
  return [
    `<svg xmlns="http://www.w3.org/2000/svg" width="${PLOT_W}" height="${PLOT_H}" viewBox="0 0 ${PLOT_W} ${PLOT_H}" font-family="-apple-system, BlinkMacSystemFont, sans-serif">`,
    `<rect width="${PLOT_W}" height="${PLOT_H}" fill="white"/>`,
    `<text x="${PLOT_W / 2}" y="26" text-anchor="middle" font-size="18" font-weight="600">Pareto Frontier — ${escapeXml(task)}</text>`,
    `<text x="${PLOT_W / 2}" y="${PLOT_H / 2}" text-anchor="middle" font-size="14" fill="#777">no measurements yet</text>`,
    `</svg>`,
  ].join("\n");
}

// ---------------------------------------------------------------------------
// IO entrypoint
// ---------------------------------------------------------------------------

export interface PlotAllOptions {
  resultsDir?: string;
  /**
   * Provide the frontier file in memory instead of reading from disk.
   * Used by tests so the plot module can stay disk-free.
   */
  frontier?: FrontierFile;
}

/**
 * Render one SVG per task class. Writes to `eval/results/plots/<task>.svg`
 * and returns the set of paths written.
 */
export function plotAllFromDisk(opts: PlotAllOptions = {}): string[] {
  const resultsDir = opts.resultsDir ?? DEFAULT_RESULTS_DIR;
  let file: FrontierFile;
  if (opts.frontier !== undefined) {
    file = opts.frontier;
  } else {
    const path = join(resultsDir, "frontier.json");
    const raw = readFileSync(path, "utf8");
    file = JSON.parse(raw) as FrontierFile;
  }
  const out: string[] = [];
  for (const [taskName, block] of Object.entries(file.tasks)) {
    const task = taskName as TaskClass;
    const svg = renderTaskPlot(task, block);
    const outPath = join(resultsDir, "plots", `${task}.svg`);
    mkdirSync(dirname(outPath), { recursive: true });
    writeFileSync(outPath, svg, "utf8");
    out.push(outPath);
  }
  return out;
}

// Tiny helper so callers can produce a plot for a single task block.
export function plotOneTask(
  task: TaskClass,
  block: FrontierTaskBlock,
): string {
  return renderTaskPlot(task, block);
}

// Re-export for tests.
export type { AllEntry };
